DELIMITER $$
--
-- Procedures
--
CREATE DEFINER=`root`@`localhost` PROCEDURE `GetJobApplicationStats` ()   BEGIN
    SELECT 
        j.title as job_title,
        COUNT(a.id) as applicant_count,
        AVG(sr.cosine_similarity_score) as avg_similarity,
        SUM(CASE WHEN sr.final_decision = 'recommended' THEN 1 ELSE 0 END) as recommended_count
    FROM jobs j
    LEFT JOIN applicants a ON j.id = a.job_id
    LEFT JOIN screening_results sr ON a.id = sr.applicant_id
    GROUP BY j.id, j.title
    ORDER BY applicant_count DESC;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `GetMonthlyApplicants` (IN `months` INT)   BEGIN
    SELECT 
        DATE_FORMAT(applied_at, '%Y-%m') as month,
        COUNT(*) as applicant_count
    FROM applicants
    WHERE applied_at >= DATE_SUB(NOW(), INTERVAL months MONTH)
    GROUP BY DATE_FORMAT(applied_at, '%Y-%m')
    ORDER BY month DESC;
END$$

CREATE DEFINER=`root`@`localhost` PROCEDURE `GetScreeningStatistics` ()   BEGIN
    SELECT 
        COUNT(*) as total_applicants,
        SUM(CASE WHEN sr.final_decision = 'recommended' THEN 1 ELSE 0 END) as recommended,
        SUM(CASE WHEN sr.final_decision = 'not_recommended' THEN 1 ELSE 0 END) as not_recommended,
        SUM(CASE WHEN sr.final_decision IS NULL THEN 1 ELSE 0 END) as pending,
        AVG(sr.cosine_similarity_score) as avg_similarity_score,
        COUNT(DISTINCT a.job_id) as total_jobs
    FROM applicants a
    LEFT JOIN screening_results sr ON a.id = sr.applicant_id;
END$$

DELIMITER ;

