--
-- Table structure for table `jobs`
--

CREATE TABLE `jobs` (
  `id` int(11) NOT NULL,
  `title` varchar(255) NOT NULL,
  `description` text NOT NULL,
  `responsibilities` text NOT NULL,
  `requirements` text NOT NULL,
  `is_active` tinyint(1) DEFAULT 1,
  `created_at` timestamp NOT NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp()
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

--
-- Dumping data for table `jobs`
--

INSERT INTO `jobs` (`id`, `title`, `description`, `responsibilities`, `requirements`, `is_active`, `created_at`, `updated_at`) VALUES
(1, 'Software Engineer', 'Kami mencari Software Engineer yang berpengalaman untuk mengembangkan aplikasi web yang scalable dan maintainable. Anda akan bekerja dalam tim yang dinamis dan menggunakan teknologi terkini seperti Python, Flask, MySQL, dan REST API.', '', '- Pengalaman 2+ tahun dalam pengembangan web dengan Python dan Flask/Django\r\n- Memahami database MySQL/PostgreSQL dan ORM\r\n- Familiar dengan REST API dan microservices architecture\r\n- Pengalaman dengan Git, Docker, dan Agile methodology\r\n- Kemampuan problem-solving dan analytical thinking yang baik', 1, '2025-10-30 03:40:41', '2026-04-30 02:51:15'),
(2, 'Data Scientist', 'Bergabunglah dengan tim data science kami untuk membangun model machine learning yang inovatif. Anda akan bekerja dengan data skala besar dan menerapkan solusi AI untuk bisnis dalam bidang predictive analytics dan NLP.', '', '- Gelar S1/S2 dalam Computer Science, Statistics, Mathematics, atau bidang terkait\r\n- Pengalaman 2+ tahun dengan Python dan library ML (scikit-learn, TensorFlow, PyTorch)\r\n- Memahami statistik, probability, dan experimental design\r\n- Pengalaman dengan SQL, data visualization, dan big data tools\r\n- Familiar dengan NLP, deep learning, dan cloud platforms (AWS/GCP)', 1, '2025-10-30 03:40:41', '2026-04-30 02:51:19'),
(3, 'Frontend Developer', 'Kami mencari Frontend Developer yang kreatif untuk membangun user interface yang menarik dan responsive. Anda akan bekerja dengan design team untuk implementasi UI/UX terbaik menggunakan React.js dan modern CSS.', '', '- Pengalaman 1+ tahun dalam frontend development\r\n- Menguasai HTML5, CSS3, JavaScript (ES6+)\r\n- Familiar dengan React.js/Vue.js dan state management\r\n- Memahami responsive design, cross-browser compatibility\r\n- Pengalaman dengan version control (Git), build tools (Webpack)\r\n- Knowledge of UI/UX principles dan design systems', 1, '2025-10-30 03:40:41', '2026-04-30 02:51:23'),
(4, 'Product Manager', 'Product Manager akan bertanggung jawab untuk mengelola product lifecycle dari konsep hingga launch. Anda akan bekerja dengan cross-functional team untuk deliver produk yang berkualitas dan sesuai kebutuhan user.', '', '- Pengalaman 3+ tahun sebagai Product Manager atau Product Owner\r\n- Kemampuan analisis bisnis, market research, dan strategic thinking\r\n- Experienced in Agile/Scrum methodology dan product development cycles\r\n- Strong communication, presentation, dan leadership skills\r\n- Memahami user-centered design principles dan analytics tools\r\n- Technical background atau understanding of software development processes', 0, '2025-10-30 03:40:41', '2026-01-10 00:03:42'),
(5, 'Backend Developer', 'Backend Developer untuk membangun sistem server-side yang robust dan scalable. Fokus pada performance optimization, security, dan integration dengan berbagai third-party services.', '', '- Pengalaman 2+ tahun dalam backend development dengan Python/Node.js/Java\r\n- Memahami database design, SQL, dan performance optimization\r\n- Familiar dengan RESTful APIs, GraphQL, dan microservices\r\n- Pengalaman dengan cloud services (AWS, Azure, GCP)\r\n- Knowledge of security best practices dan system architecture\r\n- Experience dengan Docker, Kubernetes, dan CI/CD pipelines', 1, '2025-10-30 03:40:41', '2026-04-30 02:51:26'),
(6, 'Digital Creator', 'Bertanggung jawab merancang dan mengeksekusi strategi digital marketing, termasuk pengelolaan KOL/influencer dan brand activation, serta mengelola campaign end-to-end dari perencanaan hingga analisis performa.', '- Mengembangkan dan mengeksekusi strategi digital marketing\r\n- Mengelola KOL dan influencer untuk mendukung campaign\r\n- Menjalankan end-to-end campaign (planning, execution, evaluation)\r\n- Menyusun content plan dan mendistribusikan brief ke stakeholder terkait\r\n- Mengelola hubungan dengan KOL (negosiasi, scheduling, monitoring performa)\r\n- Mengelola campaign digital dan aktivitas brand activation (online & offline)\r\n- Mengkoordinasikan partnership, live streaming, event, dan community engagement\r\n- Mengelola administrasi kampanye (agreement, invoice, report, dll.)\r\n- Berkoordinasi dengan tim internal dan eksternal\r\n- Menganalisis performa campaign (reach, engagement, traffic, conversion rate)\r\n- Mengoptimalkan strategi berdasarkan data untuk meningkatkan efektivitas campaign', '- Lulusan S1\r\n- Berpengalaman di bidang digital marketing / KOL specialist / content creator\r\n- Memahami strategi social media, influencer marketing, dan brand activation\r\n- Terbiasa mengelola end-to-end campaign digital\r\n- Mampu berkoordinasi dengan KOL/influencer dan stakeholder\r\n- Memahami analisis performa (engagement, reach, conversion rate)\r\n- Terbiasa menggunakan tools analitik (Google Analytics, Meta Insights, TikTok Analytics)\r\n- Memiliki kemampuan komunikasi dan administrasi yang baik\r\n- Mampu bekerja secara tim maupun individu', 1, '2026-04-04 07:51:38', '2026-05-15 01:02:40');

